  (E'DF-2026-036'::text, E'DF'::text, E'GIRD/ KALITEKONTROLU- UYGUNSUZLUKTESPITI | MUAYENEBILGILERI | Kayit No: 26/02/042 | Muayene Tarihi: 09.02.2026 | Tedarikgi: Saytek Tasarim Mak.kal.kons'::text, E'Tedarikçiden gelen parçalarda boyutsal, görsel veya fonksiyonel uygunsuzluk tespit edilmektedir.'::text, E'Muayenede uygunsuz parçalar, sevkiyattan önce tedarikçi tarafından eleneememektedir.'::text, E'Tedarikçi çıkış kontrol noktasında kritik karakteristikler ölçülmemekte ya da kayıt tutulmamaktadır.'::text, E'Kontrol planında kritik karakteristikler tanımlanmamış veya güncel değildir.'::text, E'Tedarikçi ile yapılan teknik toplantıda kritik özellikler yeterince vurgulanmamış, kontrol planı birlikte gözden geçirilmemiştir.'::text, E'Tedarikçi geliştirme/onay sürecinde ürün kalite planı (PPAP/APQP vb.) gerektiği düzeyde oluşturulmamış ve denetlenmemiştir.'::text, E'GIRD/ KALITEKONTROLU- UYGUNSUZLUKTESPITI | MUAYENEBILGILERI | Kayit No: 26/02/042 | Muayene Tarihi: 09.02.2026 | Tedarik'::text, E'Tedarikgi'::text, E'09.03.2026'::text, E'Tedarikgi'::text, E'Tedarikçi üretim sürecinde boyutsal/görsel/fonksiyonel kalite kontrol yeterli düzeyde uygulanmamaktadır. Kontrol planınd…'::text, E'GKK (Girdi Kalite Kontrol) muayenesinde veya saha geri bildirimi ile tespit edilmiştir.'::text, E'1. Uygunsuz \'Arka Firga Kaldirma Borusu\' partisi tedarikçiye iade edilmeli veya karantinaya alınmalıdır.\n2. Tedarikçiye DF-2026-036 numaralı DF kaydı iletilmeli, 15 iş günü içinde yazılı kök neden analizi ve düzeltici aksiyon planı talep edilmelidir.\n3. Tedarikçinin kontrol planı incelenmeli; kritik boyutlar ve kabul kriterleri yeniden belirlenmeli, onaylı kontrol planı alınmalıdır.\n4. Aynı tedarikçiden tekrarlayan uygunsuzluk varsa tedarikçi performans puanı düşürülmeli, alternatif tedarikçi değerlendirmesi başlatılmalıdır.'::text),
  (E'DF-2026-037'::text, E'DF'::text, E'HSCKaraci konteyner kaldirma islemini yaparken gdp konteyner kapagi HSCKaracina carpiyor. Gép dékme islemi | gergeklesmiyor . Manuel el ile kullanildiginda gdépler kazandan fazla yere dokiiliiyor .'::text, E'Tedarikçi kaynaklı kaynak, işleme veya montaj hataları ürünlere yansımaktadır.'::text, E'Uygunsuz ürünler tedarikçi sürecinde tespit edilemeden sevk edilmektedir.'::text, E'Tedarikçide kaynak/montaj prosedürüne uygunluk kontrol edilmemektedir.'::text, E'Tedarikçi proses kontrolü (parametre takibi, operatör eğitimi) yetersizdir.'::text, E'Tedarikçi FMEA ve kontrol planı revize edilmemiş; kritik proses adımları izlenmemektedir.'::text, E'Tedarikçi periyodik denetim ve sürekliliğini sağlayacak sistematik bir kalite geliştirme programı bulunmamaktadır.'::text, E'HSCKaraci konteyner kaldirma islemini yaparken gdp konteyner kapagi HSCKaracina carpiyor. Gép dékme islemi | gergeklesmi'::text, E'Tedarikgi'::text, E'09.03.2026'::text, E'Tedarikgi'::text, E'Tedarikçi üretim sürecinde yeterli kalite güvencesi uygulanmamaktadır'::text, E'GKK (Girdi Kalite Kontrol) muayenesinde veya saha geri bildirimi ile tespit edilmiştir.'::text, E'1. Tedarikçiye uygunsuzluk bildirimi yapılmalı ve yazılı aksiyon planı talep edilmelidir.\n2. Uygunsuz parçalar karantinaya alınarak iade süreci başlatılmalıdır.\n3. Tedarikçi ile teknik görüşme yapılarak kök neden doğrulanmalıdır.\n4. Tedarikçi performans değerlendirmesine bu kayıt işlenmelidir.'::text)
  ) AS t(nc_number, typ, problem_def, symptom, why1, why2, why3, why4, why5, ne, nerede, ne_zaman, kim, neden, nasil, actions_text)
)
UPDATE non_conformities n
SET
  five_n1k_analysis = jsonb_build_object(
    'ne', to_jsonb(x.ne),
    'nerede', to_jsonb(x.nerede),
    'neZaman', to_jsonb(x.ne_zaman),
    'kim', to_jsonb(x.kim),
    'neden', to_jsonb(x.neden),
    'nasil', to_jsonb(x.nasil)
  ),
  five_why_analysis = jsonb_build_object(
    'problem', to_jsonb(x.problem_def),
    'why1', to_jsonb(x.why1),
    'why2', to_jsonb(x.why2),
    'why3', to_jsonb(x.why3),
    'why4', to_jsonb(x.why4),
    'why5', to_jsonb(x.why5),
    'rootCause', to_jsonb(x.why5),
    'immediateAction', to_jsonb(x.neden),
    'preventiveAction', to_jsonb(x.actions_text)
  ),
  eight_d_steps = CASE
    WHEN n.type = '8D' THEN
      jsonb_set(
        jsonb_set(
          COALESCE(n.eight_d_steps, '{}'::jsonb),
          '{D4,description}',
          to_jsonb(
            ('5 Neden (özet)'::text || E'\n\n' ||
             '1. ' || x.why1 || E'\n' ||
             '2. ' || x.why2 || E'\n' ||
             '3. ' || x.why3 || E'\n' ||
             '4. ' || x.why4 || E'\n' ||
             '5 (Kök): ' || x.why5)::text
          ),
          true
        ),
        '{D5,description}',
        to_jsonb(('Önerilen düzeltici faaliyetler'::text || E'\n\n' || x.actions_text)::text),
        true
      )
    ELSE n.eight_d_steps
  END,
  updated_at = now()
FROM x
WHERE n.nc_number = x.nc_number AND n.type = x.typ;
